// Generates a committed C# source file (unity-editor-mcp/Core/CommandCatalog.g.cs)
// from the canonical catalog + VERSION, so the editor knows the declared command
// surface and protocol version without shipping the JSON. Unity compiles whatever
// C# is on disk, so the generated file is committed and verified up-to-date by
// check-drift.mjs (regenerate-and-compare). Dependency-free.
//
//   node protocol/scripts/generate-csharp-catalog.mjs   # (re)write the file

import { readFile, writeFile } from 'node:fs/promises';
import { fileURLToPath } from 'node:url';
import { dirname, resolve } from 'node:path';

const HERE = dirname(fileURLToPath(import.meta.url));
const ROOT = resolve(HERE, '..', '..');
const CATALOG = resolve(ROOT, 'protocol', 'catalog', 'commands.json');
const VERSION_FILE = resolve(ROOT, 'protocol', 'VERSION');

/** Absolute path of the generated C# file. */
export const OUTPUT = resolve(ROOT, 'unity-editor-mcp', 'Core', 'CommandCatalog.g.cs');

/** Builds the generated C# source as a string (LF line endings). */
export async function buildCatalogSource() {
  const version = (await readFile(VERSION_FILE, 'utf8')).trim();
  const catalog = JSON.parse(await readFile(CATALOG, 'utf8'));
  const editor = catalog.commands
    .filter((c) => c.sides.includes('editor'))
    .map((c) => c.name)
    .sort();
  const entries = editor.map((n) => `            "${n}",`).join('\n');
  const gaps = (catalog.knownGaps || [])
    .filter((g) => g.missing === 'editor')
    .map((g) => g.command)
    .sort();
  const gapEntries = gaps.map((n) => `            "${n}",`).join('\n');

  // Capability manifest: for every AVAILABLE editor command (sides includes 'editor',
  // minus the known editor gaps) emit {name, description, params}. The editor advertises
  // this in the handshake so the Node server learns each instance's tool surface AND its
  // schemas at runtime — the version-agnostic surface (ADR 0004). Embedded as a JSON string
  // const (parsed with JArray.Parse on the editor side); a C# verbatim literal, so only
  // double-quotes need doubling (backslashes — JSON escapes — stay literal).
  const gapSet = new Set(gaps);
  const manifest = catalog.commands
    .filter((c) => c.sides.includes('editor') && !gapSet.has(c.name) && !c.internal)
    .map((c) => ({ name: c.name, category: c.category, description: c.description, params: c.params ?? { type: 'object' } }))
    .sort((a, b) => a.name.localeCompare(b.name));
  const manifestCs = JSON.stringify(manifest).replace(/"/g, '""');

  return [
    '// <auto-generated>',
    '//     Generated from protocol/catalog/commands.json and protocol/VERSION by',
    '//     protocol/scripts/generate-csharp-catalog.mjs. DO NOT EDIT BY HAND.',
    '//     Regenerate: node protocol/scripts/generate-csharp-catalog.mjs',
    '//     Verified up-to-date in CI by protocol/scripts/check-drift.mjs.',
    '// </auto-generated>',
    'namespace UnityEditorMCP.Core',
    '{',
    '    /// <summary>The command surface declared by the protocol catalog.</summary>',
    '    public static class CommandCatalog',
    '    {',
    '        /// <summary>Protocol contract version (protocol/VERSION).</summary>',
    `        public const string ProtocolVersion = "${version}";`,
    '',
    '        /// <summary>Every command whose catalog "sides" includes "editor".</summary>',
    '        public static readonly string[] EditorCommands =',
    '        {',
    entries,
    '        };',
    '',
    '        /// <summary>Declared-but-unimplemented editor commands (catalog knownGaps).</summary>',
    '        public static readonly string[] KnownEditorGaps =',
    '        {',
    gapEntries,
    '        };',
    '',
    '        /// <summary>JSON [{name, description, params}] manifest for every available editor',
    '        /// command — the schemas the editor advertises in the handshake (ADR 0004). Parse',
    '        /// with Newtonsoft JArray.Parse.</summary>',
    `        public const string CommandManifestJson = @"${manifestCs}";`,
    '    }',
    '}',
    '',
  ].join('\n');
}

const invokedDirectly = process.argv[1] && resolve(process.argv[1]) === fileURLToPath(import.meta.url);
if (invokedDirectly) {
  const src = await buildCatalogSource();
  await writeFile(OUTPUT, src, 'utf8');
  console.log(`Wrote ${OUTPUT}`);
}
